package x509_test

import "crypto/x509"

// buildCompositeTVCases returns the 8 RSA composite IETF test vectors.
// Source: https://github.com/lamps-wg/draft-composite-sigs/blob/main/src/testvectors.json
func buildCompositeTVCases() []tvCase {
	return []tvCase{
		// id-MLDSA44-RSA2048-PSS-SHA256
		{
			alg: x509.MLDSA44_RSA2048_PSS_SHA256,
			skBytes: mustHex(
				""),
			pkBytes: mustHex(
				""),
			sig: mustHex(
				""),
		},
		// id-MLDSA44-RSA2048-PKCS15-SHA256
		{
			alg: x509.MLDSA44_RSA2048_PKCS15_SHA256,
			skBytes: mustHex(
				""),
			pkBytes: mustHex(
				""),
			sig: mustHex(
				""),
		},
		// id-MLDSA65-RSA3072-PSS-SHA512
		{
			alg: x509.MLDSA65_RSA3072_PSS_SHA512,
			skBytes: mustHex(
				""),
			pkBytes: mustHex(
				""),
			sig: mustHex(
				""),
		},
		// id-MLDSA65-RSA3072-PKCS15-SHA512
		{
			alg: x509.MLDSA65_RSA3072_PKCS15_SHA512,
			skBytes: mustHex(
				""),
			pkBytes: mustHex(
				""),
			sig: mustHex(
				""),
		},
		// id-MLDSA65-RSA4096-PSS-SHA512
		{
			alg: x509.MLDSA65_RSA4096_PSS_SHA512,
			skBytes: mustHex(
				""),
			pkBytes: mustHex(
				""),
			sig: mustHex(
				""),
		},
		// id-MLDSA65-RSA4096-PKCS15-SHA512
		{
			alg: x509.MLDSA65_RSA4096_PKCS15_SHA512,
			skBytes: mustHex(
				""),
			pkBytes: mustHex(
				""),
			sig: mustHex(
				""),
		},
		// id-MLDSA87-RSA3072-PSS-SHA512
		{
			alg: x509.MLDSA87_RSA3072_PSS_SHA512,
			skBytes: mustHex(
				""),
			pkBytes: mustHex(
				""),
			sig: mustHex(
				""),
		},
		// id-MLDSA87-RSA4096-PSS-SHA512
		{
			alg: x509.MLDSA87_RSA4096_PSS_SHA512,
			skBytes: mustHex(
				""),
			pkBytes: mustHex(
				""),
			sig: mustHex(
				""),
		},
	}
}
